public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {
        EvilATM atm = new EvilATM();

        // ── Valid transaction ──
        check("valid transaction",
              "Dispensing $100.0 for account ACC001 | Transaction logged.",
              atm.processTransaction("acc001", "100"));

        // ── Valid transaction preserves uppercase ──
        check("uppercase account ID",
              "Dispensing $50.0 for account GRU99 | Transaction logged.",
              atm.processTransaction("gru99", "50"));

        // ── NumberFormatException ──
        check("invalid amount text",
              "Error: invalid amount 'lots' | Transaction logged.",
              atm.processTransaction("acc001", "lots"));

        // ── NullPointerException ──
        check("null account ID",
              "Error: account ID cannot be null | Transaction logged.",
              atm.processTransaction(null, "200"));

        // ── IllegalArgumentException: zero ──
        check("zero amount",
              "Error: Amount must be positive | Transaction logged.",
              atm.processTransaction("acc001", "0"));

        // ── IllegalArgumentException: negative ──
        check("negative amount",
              "Error: Amount must be positive | Transaction logged.",
              atm.processTransaction("acc001", "-50"));

        // ── finally always appends log message ──
        String r = atm.processTransaction("acc999", "bad");
        boolean hasLog = r != null && r.endsWith("| Transaction logged.");
        checkBool("finally always appends log", true, hasLog);

        // ── null + bad amount: NullPointerException wins ──
        check("null ID + bad amount → NullPointerException",
              "Error: account ID cannot be null | Transaction logged.",
              atm.processTransaction(null, "notanumber"));

        // ── summary ──
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void checkBool(String label, boolean expected, boolean actual) {
        if (expected == actual) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected " + expected + " but got " + actual); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e); failed++;
    }
}
